settings.setting:
SELECT DISTINCT ?item ?itemLabel ?itemDescription ?lang ?AAT_id WHERE {
?item wdt:P1014 ?id. ?item(rdfs:label|skos:altLabel) ?itemLabel. FILTER(REGEX(?itemLabel, "^(***PLACEHOLDER***|[^ ]+ ***PLACEHOLDER***)", "i")) FILTER(LANGMATCHES(LANG(?itemLabel), "it") || LANGMATCHES(LANG(?itemLabel), "en")) ?item schema:description ?itemDescription. FILTER(LANGMATCHES(LANG(?itemDescription), "it") || LANGMATCHES(LANG(?itemDescription), "en")) FILTER(LANG(?itemLabel) = LANG(?itemDescription))
BIND(LANG(?itemLabel) AS ?lang) SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE], en, it". } BIND( CONCAT("AAT: ", "https://vocab.getty.edu/page/aat/", ?id) AS ?AAT_id) } order by ?item

SELECT DISTINCT ?item ?itemLabel ?itemDescription ?value ?lang
WHERE {

{
?item wdt:P31 wd:Q105756498 .
?item (rdfs:label|skos:altLabel) ?itemLabel.
FILTER(REGEX(?itemLabel, "^(***PLACEHOLDER***|[^ ]+ ***PLACEHOLDER***)", "i"))
?item(rdfs:label|skos:altLabel) ?itemLabel.
}
UNION
{
?item wdt:P279 wd:Q2088357 .
?item (rdfs:label|skos:altLabel) ?itemLabel.
FILTER(REGEX(?itemLabel, "^(***PLACEHOLDER***|[^ ]+ ***PLACEHOLDER***)", "i"))
?item(rdfs:label|skos:altLabel) ?itemLabel.
}
FILTER(LANGMATCHES(LANG(?itemLabel), "it") || LANGMATCHES(LANG(?itemLabel), "en"))
?item schema:description ?itemDescription.
FILTER(LANGMATCHES(LANG(?itemDescription), "it") || LANGMATCHES(LANG(?itemDescription), "en"))
FILTER(LANG(?itemLabel) = LANG(?itemDescription))

  BIND(LANG(?itemLabel) AS ?lang)
SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE, en, it". }
}
order by ?item

SELECT distinct ?item ?itemLabel ?itemDescription ?value  
WHERE {
  {?item wdt:P8516 ?value;
        rdfs:label ?itemLabel.

 FILTER((LANG(?itemLabel)) = "it") 
 FILTER(REGEX(?itemLabel, "^(***PLACEHOLDER***|[^ ]+ ***PLACEHOLDER***)", "i"))
 OPTIONAL {
    ?item schema:description ?itemDescription.
    FILTER(LANGMATCHES(LANG(?itemDescription), LANG(?itemLabel)))
  }
  }
UNION
 {
   ?item wdt:P8516 ?value;
     rdfs:label ?itemLabel.

 FILTER((LANG(?itemLabel)) = "en") 
 FILTER(REGEX(?itemLabel, "^(***PLACEHOLDER***|[^ ]+ ***PLACEHOLDER***)", "i"))
 OPTIONAL {
    ?item schema:description ?itemDescription.
    FILTER(LANGMATCHES(LANG(?itemDescription), LANG(?itemLabel)))
  }
  }
        SERVICE wikibase:label { bd:serviceParam wikibase:language "it, en". }

 }

ORDER BY ?item

