SELECT DISTINCT ?item ?itemLabel ?itemDescription ?value ?lang WHERE { ?item wdt:P8516 ?value. #FILTER (REGEX(?value, "mp", "i")) ?item (rdfs:label|skos:altLabel) ?itemLabel. FILTER(REGEX(?itemLabel, "^(***PLACEHOLDER***|[^ ]+ ***PLACEHOLDER***)", "i")) ?item(rdfs:label|skos:altLabel) ?itemLabel.
FILTER(LANGMATCHES(LANG(?itemLabel), "it") || LANGMATCHES(LANG(?itemLabel), "en")) ?item schema:description ?itemDescription. FILTER(LANGMATCHES(LANG(?itemDescription), "it") || LANGMATCHES(LANG(?itemDescription), "en")) FILTER(LANG(?itemLabel) = LANG(?itemDescription))
BIND(LANG(?itemLabel) AS ?lang) SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE], en, it". }
} order by ?item

SELECT DISTINCT ?item ?itemLabel ?itemDescription ?value ?lang ?displayLabel
WHERE {
  {
    ?item wdt:P9112 ?value ;
          rdfs:label ?itemLabel .
    FILTER(REGEX(?value, "soundatm#", "i"))
    FILTER((LANG(?itemLabel)) = "it")
    FILTER(REGEX(?itemLabel, "^(historical|[^ ]+ historical)", "i"))
    OPTIONAL {
      ?item schema:description ?itemDescription .
      FILTER(LANGMATCHES(LANG(?itemDescription), LANG(?itemLabel)))
    }
    BIND("it" AS ?lang)
  }
  UNION
  {
    ?item wdt:P9112 ?value ;
          rdfs:label ?itemLabel .
    FILTER(REGEX(?value, "soundatm#", "i"))
    FILTER((LANG(?itemLabel)) = "en")
    FILTER(REGEX(?itemLabel, "^(historical|[^ ]+ historical)", "i"))
    OPTIONAL {
      ?item schema:description ?itemDescription .
      FILTER(LANGMATCHES(LANG(?itemDescription), LANG(?itemLabel)))
    }
    BIND("en" AS ?lang)
  }

  SERVICE wikibase:label { bd:serviceParam wikibase:language "it, en". }

  BIND(
    CONCAT(
      STR(?itemLabel),
      " - ",
      ?lang,
      " [",
      STR(?item),
      "]",
      IF(
        BOUND(?itemDescription),
        CONCAT(" (", STR(?itemDescription), ")"),
        ""
      )
    ) AS ?displayLabel
  )
}
ORDER BY ?item

