SELECT DISTINCT ?item ?itemLabel ?itemDescription ?qvalue ?lang ?iflaLink ?displayLabel
WHERE {
  {
    ?item wdt:P9112 ?value ;
          (rdfs:label|skos:altLabel) ?itemLabel .
    FILTER(REGEX(?value, "soundcut#", "i"))
    FILTER(REGEX(?itemLabel, "^(***PLACEHOLDER***|[^ ]+ ***PLACEHOLDER***)", "i"))
    FILTER(LANGMATCHES(LANG(?itemLabel), "it"))
    OPTIONAL {
      ?item schema:description ?itemDescription .
      FILTER(LANGMATCHES(LANG(?itemDescription), "it"))
    }
    OPTIONAL {
      ?item wdt:P9112 ?value ;
            p:P9112/pq:P1810 ?qvalue .
    }
    OPTIONAL {
      ?item wdt:P9112 ?value ;
            p:P9112/pq:P4970 ?qvalue .
    }
    OPTIONAL {
      ?item wdt:P9112 ?value ;
            p:P9112/pq:P1810 ?qvalue .
      FILTER(REGEX(?value, "soundcut#", "i"))
      FILTER(REGEX(?qvalue, "^(***PLACEHOLDER***|[^ ]+ ***PLACEHOLDER***)", "i"))
    }
    OPTIONAL {
      ?item wdt:P9112 ?value ;
            p:P9112/pq:P4970 ?qvalue .
      FILTER(REGEX(?value, "soundcut#", "i"))
      FILTER(REGEX(?qvalue, "^(***PLACEHOLDER***|[^ ]+ ***PLACEHOLDER***)", "i"))
    }
  }
  UNION
  {
    ?item wdt:P9112 ?value ;
          (rdfs:label|skos:altLabel) ?itemLabel .
    FILTER(REGEX(?value, "soundcut#", "i"))
    FILTER(REGEX(?itemLabel, "^(***PLACEHOLDER***|[^ ]+ ***PLACEHOLDER***)", "i"))
    FILTER(LANGMATCHES(LANG(?itemLabel), "en"))
    OPTIONAL {
      ?item schema:description ?itemDescription .
      FILTER(LANGMATCHES(LANG(?itemDescription), "en"))
    }
    OPTIONAL {
      ?item wdt:P9112 ?value ;
            p:P9112/pq:P1810 ?qvalue .
    }
    OPTIONAL {
      ?item wdt:P9112 ?value ;
            p:P9112/pq:P4970 ?qvalue .
    }
    OPTIONAL {
      ?item wdt:P9112 ?value ;
            p:P9112/pq:P1810 ?qvalue .
      FILTER(REGEX(?value, "soundcut#", "i"))
      FILTER(REGEX(?qvalue, "^(***PLACEHOLDER***|[^ ]+ ***PLACEHOLDER***)", "i"))
    }
    OPTIONAL {
      ?item wdt:P9112 ?value ;
            p:P9112/pq:P4970 ?qvalue .
      FILTER(REGEX(?value, "soundcut#", "i"))
      FILTER(REGEX(?qvalue, "^(***PLACEHOLDER***|[^ ]+ ***PLACEHOLDER***)", "i"))
    }
  }

  BIND(LANG(?itemLabel) AS ?lang)

  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE], en, it". }

  BIND(
    CONCAT(
      "IFLA TERM: ",
      IF(BOUND(?qvalue), STR(?qvalue), ""),
      IF(BOUND(?qvalue), " ", ""),
      "https://www.iflastandards.info/unimarc/terms/",
      STR(?value)
    ) AS ?iflaLink
  )

  BIND(
    CONCAT(
      STR(?itemLabel),
      " - ",
      ?lang,
      " [",
      STR(?item),
      "]",
      IF(
        BOUND(?itemDescription),
        CONCAT(" (", STR(?itemDescription), ")"),
        ""
      )
    ) AS ?displayLabel
  )
}
ORDER BY ?item

