SELECT DISTINCT ?item ?keyLabel ?keyDesc ?lang ?layer ?placeLabel WHERE { # Gate di curatela (solo focus) ?item wdt:P5008 wd:Q120325256 .
# Match IT/EN su label o altLabel { ?item (rdfs:label|skos:altLabel) ?lab . FILTER(LANG(?lab) = "it") FILTER(REGEX(STR(?lab), "^(***PLACEHOLDER***|[^ ]+ ***PLACEHOLDER***)", "i")) BIND("it" AS ?lang) BIND(?lab AS ?rawKeyLabel) } UNION { ?item (rdfs:label|skos:altLabel) ?lab . FILTER(LANG(?lab) = "en") FILTER(REGEX(STR(?lab), "^(***PLACEHOLDER***|[^ ]+ ***PLACEHOLDER***)", "i")) BIND("en" AS ?lang) BIND(?lab AS ?rawKeyLabel) }
# Description (fallback incrociato IT-EN) OPTIONAL { ?item schema:description ?descIt FILTER(LANG(?descIt)="it") } OPTIONAL { ?item schema:description ?descEn FILTER(LANG(?descEn)="en") } BIND( IF(?lang="it", COALESCE(?descIt, ?descEn), COALESCE(?descEn, ?descIt) ) AS ?rawKeyDesc )
# Luogo opzionale (location, se c'è) OPTIONAL { ?item wdt:P276 ?place . OPTIONAL { ?place rdfs:label ?pIt FILTER(LANG(?pIt)="it") } OPTIONAL { ?place rdfs:label ?pEn FILTER(LANG(?pEn)="en") } BIND(STR(COALESCE(?pIt, ?pEn, "")) AS ?placeLabel) }
# Layer fisso BIND("ritual_occasion" AS ?layer)
# Stringhe plain per CA BIND(STR(?rawKeyLabel) AS ?keyLabel) BIND(STR(COALESCE(?rawKeyDesc, "")) AS ?keyDesc) } ORDER BY ?lang ?keyLabel LIMIT 200

SELECT DISTINCT
  ?item
  ?keyLabel
  ?keyDesc
  ?lang
  ?layer
  ?layerOrder
  ?context ?contextLabel
WHERE {

  # 0) Vocabolario controllato (curatela)
  ?item wdt:P5008 wd:Q120325256 .
  ?item wdt:P2579 wd:Q208365 .

  # 1) Match su label/altLabel (IT/EN) con regex iniziale
  {
    ?item (rdfs:label|skos:altLabel) ?lab .
    FILTER(LANG(?lab) = "it")
    FILTER(REGEX(STR(?lab), "^(***PLACEHOLDER***|[^ ]+ ***PLACEHOLDER***)", "i"))
    BIND("it" AS ?lang)
    BIND(?lab AS ?rawKeyLabel)
  }
  UNION
  {
    ?item (rdfs:label|skos:altLabel) ?lab .
    FILTER(LANG(?lab) = "en")
    FILTER(REGEX(STR(?lab), "^(***PLACEHOLDER***|[^ ]+ ***PLACEHOLDER***)", "i"))
    BIND("en" AS ?lang)
    BIND(?lab AS ?rawKeyLabel)
  }

  # 2) Description coerente con la lingua del ramo (fallback incrociato)
  OPTIONAL { ?item schema:description ?descIt FILTER(LANG(?descIt) = "it") }
  OPTIONAL { ?item schema:description ?descEn FILTER(LANG(?descEn) = "en") }

  BIND(
    IF(?lang="it", COALESCE(?descIt, ?descEn),
                 COALESCE(?descEn, ?descIt)
    ) AS ?rawKeyDesc
  )

  # 3) Contesto opzionale: "part of" (solo per mostrare, NON per filtrare)
  OPTIONAL {
    ?item wdt:P361 ?context .
    OPTIONAL { ?context rdfs:label ?cIt FILTER(LANG(?cIt)="it") }
    OPTIONAL { ?context rdfs:label ?cEn FILTER(LANG(?cEn)="en") }
    BIND(STR(COALESCE(?cIt, ?cEn, STRAFTER(STR(?context), "/entity/"))) AS ?contextLabel)
  }

  # 4) Layer (euristico ma leggibile; puoi aggiungere classi man mano)
  OPTIONAL {
    ?item wdt:P31/wdt:P279* wd:Q97466613 .   # carnival character
    BIND(1 AS ?oCarnivalChar)
  }
  OPTIONAL {
    ?item wdt:P31/wdt:P279* wd:Q4752840 .    # fife and drum corps
    BIND(2 AS ?oFifeDrums)
  }

  BIND(
    IF(BOUND(?oCarnivalChar), 1,
      IF(BOUND(?oFifeDrums), 2,
        9
      )
    ) AS ?layerOrder
  )

  BIND(
    IF(?layerOrder = 1, "ritual_role",
      IF(?layerOrder = 2, "ritual_music",
        "ritual_term"
      )
    ) AS ?layer
  )

  # 5) Stringhe "plain" per CA
  BIND(STR(?rawKeyLabel) AS ?keyLabel)
  BIND(STR(COALESCE(?rawKeyDesc, "")) AS ?keyDesc)
}
ORDER BY ?layerOrder ?lang ?keyLabel
LIMIT 200

SELECT DISTINCT ?item ?itemLabel ?itemDescription ?lang WHERE { ?item wdt:P5008 wd:Q120325256. ?item wdt:P2579 wd:Q208365. ?item(rdfs:label|skos:altLabel) ?itemLabel. FILTER(REGEX(?itemLabel, "^(***PLACEHOLDER***|[^ ]+ ***PLACEHOLDER***)", "i")) FILTER(LANGMATCHES(LANG(?itemLabel), "it") || LANGMATCHES(LANG(?itemLabel), "en")) ?item schema:description ?itemDescription. FILTER(LANGMATCHES(LANG(?itemDescription), "it") || LANGMATCHES(LANG(?itemDescription), "en")) FILTER(LANG(?itemLabel) = LANG(?itemDescription))
BIND(LANG(?itemLabel) AS ?lang) SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE], en, it". }
} order by ?item

SELECT DISTINCT ?item ?itemLabel ?itemDescription ?lang WHERE { ?item wdt:P5008 wd:Q120325256. ?item wdt:P2579 wd:Q208365. ?item(rdfs:label|skos:altLabel) ?itemLabel. FILTER(REGEX(?itemLabel, "^(***PLACEHOLDER***|[^ ]+ ***PLACEHOLDER***)", "i")) FILTER(LANGMATCHES(LANG(?itemLabel), "it") || LANGMATCHES(LANG(?itemLabel), "en")) ?item schema:description ?itemDescription. FILTER(LANGMATCHES(LANG(?itemDescription), "it") || LANGMATCHES(LANG(?itemDescription), "en")) FILTER(LANG(?itemLabel) = LANG(?itemDescription))
BIND(LANG(?itemLabel) AS ?lang) SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE], en, it". }
} order by ?item

SELECT DISTINCT ?item ?itemLabel ?itemDescription ?envo ?lang
WHERE {
  {
    ?item wdt:P3859 ?envo ;
          rdfs:label ?itemLabel .
    FILTER(LANG(?itemLabel) = "it")
    FILTER(REGEX(STR(?itemLabel), "(^|\\W)(***PLACEHOLDER***)(\\W|$)", "i"))
    BIND("it" AS ?lang)
  }
  UNION
  {
    ?item wdt:P3859 ?envo ;
          rdfs:label ?itemLabel .
    FILTER(LANG(?itemLabel) = "en")
    FILTER(REGEX(STR(?itemLabel), "(^|\\W)(***PLACEHOLDER***)(\\W|$)", "i"))
    BIND("en" AS ?lang)
  }
  UNION
  {
    # Se vuoi che funzioni anche digitando direttamente un codice ENVO (es. ENVO:00000446)
    ?item wdt:P3859 ?envo .
    FILTER(REGEX(STR(?envo), "***PLACEHOLDER***", "i"))
  }

  OPTIONAL {
    ?item schema:description ?itemDescription .
    FILTER(LANG(?itemDescription) IN ("it","en"))
  }

  SERVICE wikibase:label { bd:serviceParam wikibase:language "it, en". }
}
ORDER BY ?item

SELECT DISTINCT ?item ?itemLabel ?itemDescription ?value ?scientificName ?lang ?num
WHERE {
  {
    SELECT DISTINCT ?item ?lang ?num WHERE {
      {
        SERVICE wikibase:mwapi {
          bd:serviceParam wikibase:endpoint "www.wikidata.org";
                          wikibase:api "EntitySearch";
                          mwapi:search "***PLACEHOLDER***";
                          mwapi:language "it";
                          mwapi:limit "20".
          ?item wikibase:apiOutputItem mwapi:item.
          ?num  wikibase:apiOrdinal true.
        }
        BIND("it" AS ?lang)
      }
      UNION
      {
        SERVICE wikibase:mwapi {
          bd:serviceParam wikibase:endpoint "www.wikidata.org";
                          wikibase:api "EntitySearch";
                          mwapi:search "***PLACEHOLDER***";
                          mwapi:language "en";
                          mwapi:limit "20".
          ?item wikibase:apiOutputItem mwapi:item.
          ?num  wikibase:apiOrdinal true.
        }
        BIND("en" AS ?lang)
      }
    }
    ORDER BY ?lang ?num
    LIMIT 40
  }

  # deve avere Catalogue of Life ID (P10585)
  ?item wdt:P10585 ?value .

  OPTIONAL { ?item wdt:P225 ?scientificName . }

  OPTIONAL {
    ?item schema:description ?itemDescription .
    FILTER(LANG(?itemDescription) IN ("it","en"))
  }

  SERVICE wikibase:label { bd:serviceParam wikibase:language "it,en". }
}
ORDER BY ?lang ?num

SELECT DISTINCT
  ?item
  ?label
  ?description
  ?caLabel
  ?caDescription
  ?keyLabel
  ?keyDesc
  ?itemLabel
  ?itemDescription
  ?lang ?num
  ?layer ?layerOrder
  ?producedSound ?producedSoundLabel
WHERE {
  {
    SELECT DISTINCT ?item ?lang ?num WHERE {
      {
        SERVICE wikibase:mwapi {
          bd:serviceParam wikibase:endpoint "www.wikidata.org";
                          wikibase:api "EntitySearch";
                          mwapi:search "***PLACEHOLDER***";
                          mwapi:language "it";
                          mwapi:limit "40".
          ?item wikibase:apiOutputItem mwapi:item.
          ?num  wikibase:apiOrdinal true.
        }
        BIND("it" AS ?lang)
      }
      UNION
      {
        SERVICE wikibase:mwapi {
          bd:serviceParam wikibase:endpoint "www.wikidata.org";
                          wikibase:api "EntitySearch";
                          mwapi:search "***PLACEHOLDER***";
                          mwapi:language "en";
                          mwapi:limit "100".
          ?item wikibase:apiOutputItem mwapi:item.
          ?num  wikibase:apiOrdinal true.
        }
        BIND("en" AS ?lang)
      }
      UNION
      {
        SERVICE wikibase:mwapi {
          bd:serviceParam wikibase:endpoint "www.wikidata.org";
                          wikibase:api "EntitySearch";
                          mwapi:search "***PLACEHOLDER***";
                          mwapi:language "se";
                          mwapi:limit "40".
          ?item wikibase:apiOutputItem mwapi:item.
          ?num  wikibase:apiOrdinal true.
        }
        BIND("se" AS ?lang)
      }
    }
    ORDER BY ?lang ?num
    LIMIT 180
  }

  # Labels per lingua (per key coerente col ramo)
  OPTIONAL { ?item rdfs:label ?labelIt FILTER(LANG(?labelIt) = "it") }
  OPTIONAL { ?item rdfs:label ?labelEn FILTER(LANG(?labelEn) = "en") }
  OPTIONAL { ?item rdfs:label ?labelSe FILTER(LANG(?labelSe) = "se") }

  # Query string in lowercase
  BIND(LCASE("***PLACEHOLDER***") AS ?q)

  # Tieni SOLO il ramo dove la label nella lingua del ramo contiene davvero la query
  FILTER(
    ( ?lang = "it" && BOUND(?labelIt) && CONTAINS(LCASE(STR(?labelIt)), ?q) ) ||
    ( ?lang = "en" && BOUND(?labelEn) && CONTAINS(LCASE(STR(?labelEn)), ?q) ) ||
    ( ?lang = "se" && BOUND(?labelSe) && CONTAINS(LCASE(STR(?labelSe)), ?q) )
  )

  # Descrizioni per lingua (fallback: se -> en)
  OPTIONAL { ?item schema:description ?descIt FILTER(LANG(?descIt) = "it") }
  OPTIONAL { ?item schema:description ?descEn FILTER(LANG(?descEn) = "en") }
  OPTIONAL { ?item schema:description ?descSe FILTER(LANG(?descSe) = "se") }

  BIND(
    IF(?lang="it", COALESCE(?descIt, ?descEn),
      IF(?lang="en", COALESCE(?descEn, ?descIt),
                    COALESCE(?descSe, ?descEn, ?descIt)
      )
    ) AS ?tmpDesc
  )

  # layer classification
  OPTIONAL {
    VALUES ?soundRoot { wd:Q11461 wd:Q179448 }
    ?item (wdt:P279*|wdt:P31/wdt:P279*) ?soundRoot .
    BIND(1 AS ?oSound)
  }
  OPTIONAL {
    ?item (wdt:P279*|wdt:P31/wdt:P279*) wd:Q16332653 .
    BIND(2 AS ?oMeteo)
  }
  OPTIONAL {
    VALUES ?anthroRoot { wd:Q4323994 wd:Q360418 wd:Q42889 wd:Q11019 }
    ?item (wdt:P279*|wdt:P31/wdt:P279*) ?anthroRoot .
    BIND(3 AS ?oAnthro)
  }
  OPTIONAL {
    ?item wdt:P4733 ?producedSound .
    BIND(3 AS ?oAnthro2)
  }
  OPTIONAL {
    ?item (wdt:P279*|wdt:P31/wdt:P279*) wd:Q16521 .
    BIND(4 AS ?oTaxon)
  }
  OPTIONAL {
    VALUES ?eventRoot { wd:Q13418847 wd:Q1656682 }  # historical event / event
    ?item (wdt:P279*|wdt:P31/wdt:P279*) ?eventRoot .
    BIND(5 AS ?oEvent)
  }

  BIND(
    IF(BOUND(?oSound), 1,
      IF(BOUND(?oMeteo), 2,
        IF(BOUND(?oAnthro) || BOUND(?oAnthro2), 3,
          IF(BOUND(?oTaxon), 4,
            IF(BOUND(?oEvent), 5, 99)
          )
        )
      )
    ) AS ?layerOrder
  )
  FILTER(?layerOrder < 99)

  BIND(
    IF(?layerOrder = 1, "sound_type",
      IF(?layerOrder = 2, "source_meteo",
        IF(?layerOrder = 3, "source_anthro",
          IF(?layerOrder = 4, "source_taxon",
            "event_context"
          )
        )
      )
    ) AS ?layer
  )

  # Label service: fornisce ?itemLabel / ?itemDescription (+ producedSoundLabel)
  SERVICE wikibase:label { bd:serviceParam wikibase:language "it,en,se". }

  # keyLabel coerente col ramo + fallback su itemLabel + fallback su QID (stringa nuda)
  BIND(
    STR(
      COALESCE(
        IF(?lang="it", ?labelIt,
          IF(?lang="en", ?labelEn, ?labelSe)
        ),
        ?itemLabel,
        STRAFTER(STR(?item), "/entity/")
      )
    ) AS ?keyLabel
  )

  # keyDesc robusta: tmpDesc -> itemDescription -> "" (stringa nuda)
  BIND(STR(COALESCE(?tmpDesc, ?itemDescription, "")) AS ?keyDesc)

  # Alias “CA-friendly” SENZA toccare itemLabel/itemDescription
  BIND(?keyLabel AS ?label)
  BIND(?keyDesc  AS ?description)
  BIND(?keyLabel AS ?caLabel)
  BIND(?keyDesc  AS ?caDescription)
}
ORDER BY ?layerOrder ?lang ?num
LIMIT 100

